1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const FIRST_INSURANCE_RATE = 0.1;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const FOLLOWUP_DISCOUNT_RATE = 0.15;
33	
34	function itemSurcharge(item: Item): number {
35	  const itemBase = BASE_PREMIUMS[item.type];
36	  let surcharge = 0;
37	  if (item.cursed) surcharge += itemBase * CURSE_SURCHARGE_RATE;
38	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
39	    surcharge += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
40	  }
41	  return surcharge;
42	}
43	
44	function typeSubtotal(type: string, count: number): number {
45	  const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
46	  return isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
47	}
48	
49	function loyaltyDiscount(customer: Customer, policyBase: number): number {
50	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
51	    ? policyBase * LOYALTY_DISCOUNT_RATE
52	    : 0;
53	}
54	
55	export function quote(customer: Customer, items: Item[]): number {
56	  const countsByType: Record<string, number> = {};
57	  for (const item of items) {
58	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
59	  }
60	
61	  const policyBase = Object.entries(countsByType)
62	    .reduce((sum, [type, count]) => sum + typeSubtotal(type, count), 0);
63	
64	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
65	  const loyalty = loyaltyDiscount(customer, policyBase);
66	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
67	  const followup = customer.previousContracts >= 1 ? policyBase * FOLLOWUP_DISCOUNT_RATE : 0;
68	
69	  return Math.ceil(policyBase + itemSurcharges - loyalty + firstInsurance - followup) + PROCESSING_FEE;
70	}
